use Math::Prime::XS qw/is_prime/;
use Math::Combinatorics;
use List::Util qw/all sum/;

sub digit_repeat {
    my $n = shift;
    my @num_list = split //, $n;
    my %seen;
    ++$seen{$_} for @num_list;
    return !(all { $seen{$_} == 1 } keys %seen);
}

sub sum_of_digits {
    my $n = shift;
    my @digits = split //, $n;
    return sum @digits;
}

